module mux_4to1 (obf_D, S, EN, Y);
input [3:0] obf_D;
input [1:0] S;
input EN;
output reg Y;

always @(*) begin
    if (EN) begin
        case (S)
            2'b00: Y = obf_D[0];
            2'b01: Y = obf_D[1];
            2'b10: Y = obf_D[2];
            2'b11: Y = obf_D[3];
            default: Y = 1'b0;
        endcase
    end
    else begin
        Y = 1'b0;
    end
end

endmodule
